import{_ as a,c as i,o as t,ag as l}from"./chunks/framework.S-Qvb3wi.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"daily/javaScript-07-BOM、DOM、事件、JS动画.md","filePath":"daily/javaScript-07-BOM、DOM、事件、JS动画.md"}'),r={name:"daily/javaScript-07-BOM、DOM、事件、JS动画.md"};function s(m,e,o,n,u,d){return t(),i("div",null,e[0]||(e[0]=[l('<h2 id="requestanimationframe-和-settimeout-setinterval-有什么区别" tabindex="-1">requestAnimationFrame 和 setTimeout/setInterval 有什么区别？ <a class="header-anchor" href="#requestanimationframe-和-settimeout-setinterval-有什么区别" aria-label="Permalink to &quot;requestAnimationFrame 和 setTimeout/setInterval 有什么区别？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>在 requestAnimationFrame 出现之前，主要使用 setTimeout/setInterval 来编写 JS 动画，但是 setTimeout/setInterval 有一个显著的缺陷就是时间是不精确的，setTimeout/setInterval 只能保证延时或者间隔不小于设定时间。</li><li>requestAnimationFrame 是浏览器用于定时循环操作的一个接口，类似于 setTimeout，主要用途是按帧对网页进行重绘，让各种网页动画效果（DOM 动画、Canvas 动画、SVG 动画、WebGL 动画）能够有一个统一的刷新机制，从而节省系统资源，提高系统性能，改善视觉效果。</li><li>requestAnimationFrame 不需要设置时间，采用系统时间间隔（帧率）</li><li>requestAnimationFrame 一旦页面不处于当前标签页就会自动停止刷新</li><li>requestAnimationFrame 是在主线程完成的，如果主线程非常繁忙，动画效果会打折扣</li></ul></details><h2 id="什么是事件-什么是事件流-浏览器事件代理机制的原理是什么-为什么需要事件代理" tabindex="-1">什么是事件？什么是事件流？浏览器事件代理机制的原理是什么？为什么需要事件代理？ <a class="header-anchor" href="#什么是事件-什么是事件流-浏览器事件代理机制的原理是什么-为什么需要事件代理" aria-label="Permalink to &quot;什么是事件？什么是事件流？浏览器事件代理机制的原理是什么？为什么需要事件代理？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>指的是在浏览器中发生的可以被监听的动作或变化</li><li>是浏览器处理事件的顺序机制，即当事件发生时，它是如何从 DOM 树中的某个节点传播的。IE 最早使用的是事件冒泡事件流，而网景采用的是事件捕获。DOM2 把事件流分为三个阶段，捕获阶段、目标阶段、冒泡阶段，现代浏览器遵循的就是此规范。</li><li>事件代理又称为事件委托，在祖先 DOM 元素绑定一个事件，当触发子孙级的 DOM 元素事件时利用事件冒泡的原理来触发绑定在祖先级 DOM 的事件。因为事件会从目标元素一层层冒泡至 document 对象。</li><li>原因： <ul><li>添加到页面上的事件数量会影响页面的运行性能，如果添加的事件过多，会导致网页性能下降。采用事件代理的方式可以大大减少注册事件的个数。</li><li>适用于动态增加的元素。</li><li>不用担心注册了事件的 DOM 元素被移除后，可能无法回收其事件处理程序的问题。</li></ul></li></ul></details><h2 id="dom-节点创建和修改有哪些常用的-api" tabindex="-1">DOM 节点创建和修改有哪些常用的 API？ <a class="header-anchor" href="#dom-节点创建和修改有哪些常用的-api" aria-label="Permalink to &quot;DOM 节点创建和修改有哪些常用的 API？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>创建节点 <ul><li>createElement</li><li>createTextNode</li><li>createDocumentFragment</li></ul></li><li>修改节点 <ul><li>appendChild</li><li>insertBefore</li><li>removeChild</li><li>replaceChild</li></ul></li></ul></details>',6)]))}const h=a(r,[["render",s]]);export{_ as __pageData,h as default};
